'DECLARE
  l_card_id        NUMBER;
  l_card_exists    NUMBER;
  l_card_label     NVARCHAR2(500);
  l_card_sm_label  VARCHAR2(255);
  l_is_card_view   VARCHAR2(10);
  l_collapse_rest  VARCHAR2(10);
  l_activities     CLOB;
  l_final_json     CLOB;
  l_offset         NUMBER := 1;
  l_chunk_size     NUMBER := 32000;
  l_length         NUMBER;
  l_buffer         VARCHAR2(32767);
BEGIN
  -- [CORS HEADERS]
  OWA_UTIL.MIME_HEADER(''application/json'', FALSE);
  HTP.P(''Access-Control-Allow-Origin: *'');
  HTP.P(''Access-Control-Allow-Methods: GET, POST, OPTIONS'');
  HTP.P(''Access-Control-Allow-Headers: Content-Type'');

  -- A. Validate ID
  BEGIN
      l_card_id := TO_NUMBER(:id);
  EXCEPTION WHEN OTHERS THEN
      HTP.P(''Content-Length: 26'');
      OWA_UTIL.HTTP_HEADER_CLOSE;
      HTP.PRN(''{"error": "Invalid ID"}'');
      RETURN;
  END;

  -- B. Fetch Card Details
  SELECT COUNT(*), MAX(LABEL), MAX(SM_LABEL), MAX(IS_CARD_VIEW), MAX(COLLAPSE_REST)
  INTO l_card_exists, l_card_label, l_card_sm_label, l_is_card_view, l_collapse_rest
  FROM CURRICULUM_CARDS
  WHERE ID = l_card_id;

  IF l_card_exists = 0 THEN
      HTP.P(''Content-Length: 30'');
      OWA_UTIL.HTTP_HEADER_CLOSE;
      HTP.PRN(''{"error": "Card not found"}'');
      RETURN;
  END IF;

  -- C. Fetch Activities and Group them by CHAPTER_NAME dynamically
  SELECT JSON_ARRAYAGG(
      JSON_OBJECT(
          ''type''     VALUE ''chapter'',
          ''label''    VALUE NVL(c.CHAPTER_NAME, l_card_label),
          ''id''       VALUE ''chap-'' || ROWNUM,
          ''desc''     VALUE c.CHAPTER_DESC,
          ''icon''     VALUE c.CHAPTER_ICON,
          ''style''    VALUE CASE WHEN c.CHAPTER_BG_COLOR IS NOT NULL 
                                THEN JSON_OBJECT(''backgroundColor'' VALUE c.CHAPTER_BG_COLOR) 
                                ELSE NULL END,
          ''list''     VALUE TREAT(c.ACT_LIST AS JSON)
          RETURNING CLOB
      ) ORDER BY c.MIN_ID ASC RETURNING CLOB
  )
  INTO l_activities
  FROM (
      SELECT 
          CHAPTER_NAME,
          MIN(a.ID) as MIN_ID, 
          MAX(CHAPTER_DESC) as CHAPTER_DESC,
          MAX(CHAPTER_ICON) as CHAPTER_ICON,
          MAX(CHAPTER_BG_COLOR) as CHAPTER_BG_COLOR,
          JSON_ARRAYAGG(
              JSON_OBJECT(
                  ''label''    VALUE a.LABEL,
                  ''id''       VALUE a.ID,
                  ''type''     VALUE a.ACTIVITY_TYPE,
                  ''btnLabel'' VALUE a.BTN_LABEL,
                  ''data''     VALUE COALESCE(JSON_QUERY(d.DATA_JSON, ''$'' RETURNING CLOB), JSON_OBJECT(RETURNING CLOB))
                  RETURNING CLOB
              ) ORDER BY a.ID ASC
              RETURNING CLOB
          ) AS ACT_LIST
      FROM ACTIVITIES a
      LEFT JOIN ACTIVITY_DATA d ON a.ID = d.ACTIVITY_ID
      WHERE a.CARD_ID = l_card_id
      GROUP BY CHAPTER_NAME
  ) c;

  IF l_activities IS NULL THEN l_activities := ''[]''; END IF;

  -- D. Construct Final JSON 
  SELECT JSON_SERIALIZE(
    JSON_OBJECT(
      ''label''        VALUE l_card_label,     
      ''altLabel''     VALUE l_card_sm_label,  
      ''id''           VALUE ''card-p'' || l_card_id,
      ''type''         VALUE ''nested'',
      ''cardView''     VALUE CASE WHEN NVL(l_is_card_view, ''false'') = ''true'' THEN ''true'' ELSE ''false'' END FORMAT JSON,
      ''collapseRest'' VALUE CASE WHEN NVL(l_collapse_rest, ''false'') = ''true'' THEN ''true'' ELSE ''false'' END FORMAT JSON,
      ''loadFirstAct'' VALUE CASE WHEN NVL(l_is_card_view, ''false'') = ''true'' THEN ''false'' ELSE ''true'' END FORMAT JSON,

      -- ADDING MISSING SUBCARDS STYLING
      ''iconStyle''    VALUE CASE WHEN NVL(l_is_card_view, ''false'') = ''true'' THEN JSON_OBJECT(''width'' VALUE 120, ''height'' VALUE 120) ELSE NULL END,
      ''cardStyle''    VALUE CASE WHEN NVL(l_is_card_view, ''false'') = ''true'' THEN JSON_OBJECT(''width'' VALUE 430, ''margin'' VALUE ''15px'', ''padding'' VALUE ''15px'', ''borderRadius'' VALUE 10, ''boxShadow'' VALUE ''var(--shadow)'', ''border'' VALUE ''1px solid #999'') ELSE NULL END,

      ''list''         VALUE TREAT(l_activities AS JSON) 
      RETURNING CLOB
    ) RETURNING CLOB
  ) INTO l_final_json FROM DUAL;

  -- E. SEND OUTPUT
  l_length := DBMS_LOB.GETLENGTH(l_final_json);
  HTP.P(''Content-Length: '' || l_length);
  OWA_UTIL.HTTP_HEADER_CLOSE;

  WHILE l_offset <= l_length LOOP
      DBMS_LOB.READ(l_final_json, l_chunk_size, l_offset, l_buffer);
      HTP.PRN(l_buffer);
      l_offset := l_offset + l_chunk_size;
  END LOOP;

EXCEPTION WHEN OTHERS THEN
  OWA_UTIL.HTTP_HEADER_CLOSE;
  HTP.PRN(''{"error": "'' || SQLERRM || ''"}'');
END;'
      );

