    SELECT count(*), MAX(admin_name), MAX(email), MAX(role)
      INTO l_count, l_name, l_email, l_role
      FROM lms_admins
     WHERE LOWER(email) = LOWER(:email)
       AND password_hash = RAWTOHEX(STANDARD_HASH(:password, ''SHA256''));

    IF l_count > 0 THEN
        UPDATE lms_admins SET last_login_at = SYSTIMESTAMP WHERE email = l_email;
        COMMIT;
        HTP.P(''{"status": "SUCCESS", "user": {"email": "''||l_email||''", "name": "''||l_name||''", "role": "''||l_role||''"}}'');
    ELSE
        OWA_UTIL.status_line(401);
        HTP.P(''{"status": "ERROR", "message": "Invalid credentials"}'');
    END IF;
END;'
