'
        BEGIN
            OWA_UTIL.MIME_HEADER(''application/json'', FALSE);
            HTP.P(''Access-Control-Allow-Origin: *'');
            OWA_UTIL.HTTP_HEADER_CLOSE;

            MERGE INTO completedword_attempts t
            USING (
                SELECT TO_NUMBER(:user_id) AS src_uid, :activity_id AS src_aid FROM dual
            ) s
            ON (t.user_id = s.src_uid AND t.activity_id = s.src_aid)
            WHEN MATCHED THEN
                UPDATE SET
                    t.progress_json = :progress_json,
                    t.score = :score,
                    t.attempted = :attempted,
                    t.status = ''IN_PROGRESS'',
                    t.updated_at = SYSTIMESTAMP
            WHEN NOT MATCHED THEN
                INSERT (user_id, activity_id, progress_json, score, attempted, status, started_at)
                VALUES (s.src_uid, s.src_aid, :progress_json, :score, :attempted, ''IN_PROGRESS'', SYSTIMESTAMP);

            COMMIT;
            HTP.P(''{"status":"success"}'');
        END;'
      );
