      p_comments       => NULL,
      p_source         => 
'DECLARE
    l_first BOOLEAN := TRUE;
    l_chunk VARCHAR2(32767);
    l_offset NUMBER;
BEGIN
    -- 1. [CORS HEADERS]
    OWA_UTIL.MIME_HEADER(''application/json'', FALSE);
    HTP.P(''Access-Control-Allow-Origin: *'');
    OWA_UTIL.HTTP_HEADER_CLOSE;

    -- 2. START JSON ARRAY
    HTP.PRN(''{"items": ['');

    -- 3. LOOP THROUGH EVERY ROW MANUALLY (Bypasses the 4000 char limit!)
    FOR r IN (
        SELECT a.id, a.card_id, a.label, a.activity_type, a.btn_label, d.data_json
        FROM ACTIVITIES a
        LEFT JOIN ACTIVITY_DATA d ON a.id = d.activity_id
    ) LOOP
        IF NOT l_first THEN
            HTP.PRN('','');
        END IF;
        l_first := FALSE;

        -- 4. PRINT JSON PROPERTIES
        HTP.PRN(''{"id": "'' || REPLACE(r.id, ''"'', ''\"'') || ''",'');
        HTP.PRN(''"card_id": "'' || NVL(TO_CHAR(r.card_id), '''') || ''",'');
        HTP.PRN(''"label": "'' || NVL(REPLACE(r.label, ''"'', ''\"''), '''') || ''",'');
        HTP.PRN(''"activity_type": "'' || NVL(r.activity_type, '''') || ''",'');
        HTP.PRN(''"btn_label": "'' || NVL(REPLACE(r.btn_label, ''"'', ''\"''), '''') || ''",'');

        HTP.PRN(''"data_json": '');

        -- 5. STREAM THE LARGE CLOB DIRECTLY
        IF r.data_json IS NOT NULL THEN
            l_offset := 1;
            WHILE l_offset <= DBMS_LOB.GETLENGTH(r.data_json) LOOP
                l_chunk := DBMS_LOB.SUBSTR(r.data_json, 8191, l_offset);
                HTP.PRN(l_chunk);
                l_offset := l_offset + 8191;
            END LOOP;
        ELSE
            HTP.PRN(''{}'');
        END IF;

        HTP.PRN(''}'');
    END LOOP;

    -- 6. END JSON ARRAY
    HTP.PRN('']}'');
EXCEPTION WHEN OTHERS THEN
    HTP.PRN(''{"error": "API Execution Error"}'');
END;'
