  ORDS.DEFINE_TEMPLATE(
      p_module_name    => 'lms_admin',
      p_pattern        => 'save',
      p_priority       => 0,
      p_etag_type      => 'HASH',
      p_etag_query     => NULL,
      p_comments       => NULL);
  ORDS.DEFINE_HANDLER(
      p_module_name    => 'lms_admin',
      p_pattern        => 'save',
      p_method         => 'POST',
      p_source_type    => 'plsql/block',
      p_items_per_page =>  0,
      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'
      DECLARE
        l_blob        BLOB;
        l_body        CLOB;
        l_dest_offset INTEGER := 1;
        l_src_offset  INTEGER := 1;
        l_lang_context INTEGER := 0; -- DBMS_LOB.default_lang_ctx
        l_warning      INTEGER;

        l_act_id      VARCHAR2(100);
        l_card_id     NUMBER;
        l_label       VARCHAR2(500);
        l_type        VARCHAR2(100);
        l_btn_label   VARCHAR2(100);
        l_data_json   CLOB;
        l_new_id      VARCHAR2(100);
      BEGIN
        -- CORS HEADERS
        OWA_UTIL.MIME_HEADER(''application/json'', FALSE);
        HTP.P(''Access-Control-Allow-Origin: *'');
        HTP.P(''Access-Control-Allow-Methods: POST, OPTIONS'');
        HTP.P(''Access-Control-Allow-Headers: Content-Type'');
        OWA_UTIL.HTTP_HEADER_CLOSE;

        -- FIX: Read the Implicit Bind Variable :body (BLOB)
        l_blob := :body;

        IF l_blob IS NULL OR DBMS_LOB.GETLENGTH(l_blob) = 0 THEN
           HTP.P(''{"status":"error", "message":"Empty Body"}'');
           RETURN;
        END IF;

        -- CONVERT BLOB TO CLOB (Safe for all DB versions)
        DBMS_LOB.CREATETEMPORARY(l_body, TRUE);
        DBMS_LOB.CONVERTTOCLOB(
             dest_lob     => l_body,
             src_blob     => l_blob,
             amount       => DBMS_LOB.LOBMAXSIZE,
             dest_offset  => l_dest_offset,
             src_offset   => l_src_offset,
             blob_csid    => 0, -- DBMS_LOB.default_csid
             lang_context => l_lang_context,
             warning      => l_warning
        );

        -- Extract Data using JSON_TABLE
        SELECT 
           jt.activity_id, jt.card_id, jt.label, jt.type_val, jt.btn_label, jt.data_json
        INTO 
           l_act_id, l_card_id, l_label, l_type, l_btn_label, l_data_json
        FROM JSON_TABLE(l_body, ''$''
           COLUMNS (
             activity_id  VARCHAR2(100) PATH ''$.activity_id'',
             card_id      NUMBER        PATH ''$.card_id'',
             label        VARCHAR2(500) PATH ''$.label'',
             type_val     VARCHAR2(100) PATH ''$.type'',
             btn_label    VARCHAR2(100) PATH ''$.btn_label'',
             data_json    CLOB          PATH ''$.data_json''
           )
        ) jt;

        -- INSERT OR UPDATE
        IF l_act_id IS NULL OR l_act_id = '''' THEN
           l_new_id := ''act-'' || TO_CHAR(SYSTIMESTAMP, ''YYYYMMDDHH24MISSFF3'');

           INSERT INTO ACTIVITIES (id, card_id, label, activity_type, btn_label)
           VALUES (l_new_id, l_card_id, l_label, l_type, l_btn_label);

           INSERT INTO ACTIVITY_DATA (activity_id, data_json)
           VALUES (l_new_id, l_data_json);

           HTP.P(''{"status":"success", "action":"inserted", "id":"'' || l_new_id || ''"}'');
        ELSE
           UPDATE ACTIVITIES 
           SET card_id = l_card_id, label = l_label, activity_type = l_type, btn_label = l_btn_label
           WHERE id = l_act_id;

           MERGE INTO ACTIVITY_DATA d
           USING (SELECT l_act_id as aid, l_data_json as djson FROM DUAL) s
           ON (d.activity_id = s.aid)
           WHEN MATCHED THEN UPDATE SET d.data_json = s.djson
           WHEN NOT MATCHED THEN INSERT (activity_id, data_json) VALUES (s.aid, s.djson);

           HTP.P(''{"status":"success", "action":"updated"}'');
        END IF;

        COMMIT;
        DBMS_LOB.FREETEMPORARY(l_body);

      EXCEPTION WHEN OTHERS THEN
        HTP.P(''{"status":"error", "message":"'' || SQLERRM || ''"}'');
        ROLLBACK;
      END;'
      );

