      p_module_name    => 'lms_module',
      p_base_path      => '/lms/',
      p_items_per_page =>  25,
      p_status         => 'PUBLISHED',
      p_comments       => 'Module for User Dashboard Data');      
  ORDS.DEFINE_TEMPLATE(
      p_module_name    => 'lms_module',
      p_pattern        => 'v1/users/latest',
      p_priority       => 0,
      p_etag_type      => 'HASH',
      p_etag_query     => NULL,
      p_comments       => NULL);
  ORDS.DEFINE_HANDLER(
      p_module_name    => 'lms_module',
      p_pattern        => 'v1/users/latest',
      p_method         => 'GET',
      p_source_type    => 'plsql/block',
      p_items_per_page =>  0,
      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'
        DECLARE
            v_first BOOLEAN := TRUE;
        BEGIN
            -- RESPONSE HEADERS (Crucial for fixing the CORS errors you saw)
            OWA_UTIL.MIME_HEADER(''application/json'', FALSE);
            HTP.P(''Access-Control-Allow-Origin: *'');
            HTP.P(''Access-Control-Allow-Methods: GET, POST, OPTIONS'');
            HTP.P(''Access-Control-Allow-Headers: Content-Type'');
            OWA_UTIL.HTTP_HEADER_CLOSE;

            -- START JSON CONSTRUCTION
            HTP.P(''{"items":['');

            -- FETCH LATEST USERS
            FOR r IN (
                SELECT 
                    user_id, 
                    salutation, 
                    INITCAP(parent_name) as parent_name, 
                    INITCAP(child_name) as child_name, 
                    LOWER(user_level) as user_level, 
                    mobile, 
                    email, 
                    TO_CHAR(created_at, ''YYYY-MM-DD"T"HH24:MI:SS"Z"'') as created_at
                FROM lms_users
                ORDER BY created_at DESC
                FETCH FIRST 10 ROWS ONLY
            ) LOOP
                IF NOT v_first THEN
                    HTP.P('','');
                END IF;

                HTP.P(
                    ''{'' ||
                    ''"user_id":''     || r.user_id     || '','' ||
                    ''"salutation":"''  || r.salutation  || ''",'' ||
                    ''"parent_name":"'' || r.parent_name || ''",'' ||
                    ''"child_name":"''  || r.child_name  || ''",'' ||
                    ''"user_level":"''  || r.user_level  || ''",'' ||
                    ''"mobile":"''      || r.mobile      || ''",'' ||
                    ''"email":"''       || r.email       || ''",'' ||
                    ''"created_at":"''   || r.created_at  || ''"'' ||
                    ''}''
                );
                v_first := FALSE;
            END LOOP;

            HTP.P('']} '');
        EXCEPTION
            WHEN OTHERS THEN
                HTP.P(''{"message":"Server Error: '' || SQLERRM || ''", "status":"error"}'');
        END;'
      );

