'DECLARE
    v_user_id NUMBER;
    v_parent  VARCHAR2(200); -- Increased size for combined names
    v_child   VARCHAR2(200); -- Increased size for combined names
BEGIN
    -- 1. Set Headers
    OWA_UTIL.MIME_HEADER(''application/json'', FALSE);
    HTP.P(''Access-Control-Allow-Origin: *'');
    OWA_UTIL.HTTP_HEADER_CLOSE;

    -- 2. Fetch data from the new columns
    -- We concatenate First and Last names with a space in between
    SELECT user_id, 
           (p_first_name || '' '' || p_last_name), 
           (c_first_name || '' '' || c_last_name)
      INTO v_user_id, v_parent, v_child
      FROM lms_users
     WHERE LOWER(email) = LOWER(:email)
       AND password_hash = STANDARD_HASH(:password, ''SHA256'');

    -- 3. Output JSON Response
    -- We use INITCAP to ensure the names look professional (e.g., "John Doe")
    HTP.P(''{'' ||
          ''"status":"success", '' ||
          ''"user_id":'' || v_user_id || '', '' ||
          ''"user":"'' || INITCAP(v_parent) || ''", '' ||
          ''"child_name":"'' || INITCAP(v_child) || ''", '' ||
          ''"message":"Login Success!"'' ||
          ''}'');

EXCEPTION
    WHEN NO_DATA_FOUND THEN
        -- Standard error for wrong email/password
        HTP.P(''{"status":"error", "message":"Invalid credentials"}'');
    WHEN OTHERS THEN
        -- Generic server error for debugging
        HTP.P(''{"status":"error", "message":"Server Error: '' || SQLERRM || ''"}'');
END;'
      );
