      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'DECLARE
    v_count NUMBER;
BEGIN
    -- 1. Standard Headers
    OWA_UTIL.MIME_HEADER(''application/json'', FALSE);
    HTP.P(''Access-Control-Allow-Origin: *'');
    OWA_UTIL.HTTP_HEADER_CLOSE;

    -- 2. Check if Email already exists
    SELECT COUNT(*) INTO v_count FROM lms_users WHERE LOWER(email) = LOWER(:email);
    IF v_count > 0 THEN
        HTP.P(''{"status":"error", "message":"This Email Address is already registered!"}'');
        RETURN;
    END IF;

    -- 3. Check if Mobile already exists
    SELECT COUNT(*) INTO v_count FROM lms_users WHERE mobile = :mobile;
    IF v_count > 0 THEN
        HTP.P(''{"status":"error", "message":"This Mobile Number is already registered!"}'');
        RETURN;
    END IF;

    -- 4. If no duplicates, proceed with Insert
    INSERT INTO lms_users (
        salutation, 
        p_first_name, p_last_name, 
        c_first_name, c_last_name, 
        user_level, mobile, email, 
        password_hash,
        user_package
    )
    VALUES (
        :salutation, 
        :p_first_name, :p_last_name, 
        :c_first_name, :c_last_name, 
        :level, :mobile, :email, 
        STANDARD_HASH(:password, ''SHA256''),
        :package_type
    );

    COMMIT;
    HTP.P(''{"status":"success", "message":"Registered Successfully!"}'');

EXCEPTION
    WHEN OTHERS THEN
        -- Catch any other unexpected database errors
        HTP.P(''{"status":"error", "message":"Server Error: ''||SQLERRM||''"}'');
END;'
      );

