BEGIN
    -- Headers
    OWA_UTIL.MIME_HEADER(''application/json'', FALSE);
    HTP.P(''Access-Control-Allow-Origin: *'');
    OWA_UTIL.HTTP_HEADER_CLOSE;

    MERGE INTO matchby_attempts t
    USING (
        SELECT
            TO_NUMBER(:user_id) AS src_user_id,
            :activity_id        AS src_activity_id
        FROM dual
    ) s
    ON (t.user_id = s.src_user_id AND t.activity_id = s.src_activity_id)
    WHEN MATCHED THEN
        UPDATE SET
            t.progress_json = :progress_json,
            t.score         = :score,
            t.attempted     = :attempted,
            t.status        = :status,
            t.updated_at    = SYSTIMESTAMP
    WHEN NOT MATCHED THEN
        INSERT (
            user_id,
            activity_id,
            progress_json,
            score,
            attempted,
            status,
            started_at
        )
        VALUES (
            s.src_user_id,
            s.src_activity_id,
            :progress_json,
            :score,
            :attempted,
            :status,
            SYSTIMESTAMP
        );

    COMMIT;

    HTP.P(''{"status":"success","message":"Progress saved"}'');

EXCEPTION
    WHEN OTHERS THEN
        HTP.P(
            ''{"status":"error","message":"'' ||
            REPLACE(SQLERRM, ''"'', '''') ||
            ''"}''
        );
END;'
      );
