                    :activity_id AS activity_id
                FROM dual
            ) s
            ON (t.user_id = s.user_id AND t.activity_id = s.activity_id)
            WHEN MATCHED THEN
                UPDATE SET
                    t.progress_json = :progress_json,
                    t.score = :score,
                    t.attempted = :attempted,
                    t.status = :status,
                    t.updated_at = SYSTIMESTAMP
            WHEN NOT MATCHED THEN
                INSERT (
                    user_id,
                    activity_id,
                    progress_json,
                    score,
                    attempted,
                    status,
                    started_at
                )
                VALUES (
                    :user_id,
                    :activity_id,
                    :progress_json,
                    :score,
                    :attempted,
                    :status,
                    SYSTIMESTAMP
                );

            COMMIT;

            HTP.P(''{"status":"success","message":"Progress saved"}'');

        EXCEPTION
            WHEN OTHERS THEN
                HTP.P(''{"status":"error","message":"Server error"}'');
        END;'
      );
