      p_source_type    => 'plsql/block',
      p_items_per_page =>  0,
      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'
        DECLARE
            v_json CLOB;
        BEGIN
            -- RESPONSE HEADERS
            OWA_UTIL.MIME_HEADER(''application/json'', FALSE);
            HTP.P(''Access-Control-Allow-Origin: *'');

            -- ANTI-CACHING HEADERS: These force the browser to ask the server for fresh data
            -- instead of showing the "Summary" from a previous session.
            HTP.P(''Cache-Control: no-cache, no-store, must-revalidate'');
            HTP.P(''Pragma: no-cache'');
            HTP.P(''Expires: 0'');

            OWA_UTIL.HTTP_HEADER_CLOSE;

            -- SELECT DATA
            SELECT progress_json
            INTO v_json
            FROM mcq_attempts
            WHERE user_id = :user_id
              AND activity_id = :activity_id;

            -- OUTPUT JSON
            HTP.P(v_json);

        EXCEPTION
            WHEN NO_DATA_FOUND THEN
                -- If the row was deleted, we return this status so mcq.js starts fresh
                HTP.P(''{"status":"empty"}'');
            WHEN OTHERS THEN
                HTP.P(''{"status":"error","message":"Server error"}'');
        END;'
      );

