      p_comments       => NULL);
  ORDS.DEFINE_HANDLER(
      p_module_name    => 'session_mgmt_module',
      p_pattern        => 'logout',
      p_method         => 'POST',
      p_source_type    => 'plsql/block',
      p_items_per_page =>  0,
      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'
        DECLARE
            -- Independent logging procedure
            PROCEDURE log_exit(p_email VARCHAR2, p_stat VARCHAR2) IS
                PRAGMA AUTONOMOUS_TRANSACTION;
            BEGIN
                INSERT INTO logout_history (user_email, status, logout_time)
                VALUES (p_email, p_stat, CURRENT_TIMESTAMP);
                COMMIT;
            EXCEPTION
                WHEN OTHERS THEN ROLLBACK;
            END;
        BEGIN
            -- CORS and JSON Headers
            OWA_UTIL.MIME_HEADER(''application/json'', FALSE);
            HTP.P(''Access-Control-Allow-Origin: *'');
            HTP.P(''Access-Control-Allow-Headers: Content-Type'');
            HTP.P(''Access-Control-Allow-Methods: POST'');
            OWA_UTIL.HTTP_HEADER_CLOSE;

            -- Perform Logging
            log_exit(:email, ''SUCCESS'');

            -- Return Success JSON
            HTP.P(''{"status":"success", "message":"Logout recorded successfully"}'');

        EXCEPTION
            WHEN OTHERS THEN
                log_exit(:email, ''ERROR: '' || SUBSTR(SQLERRM, 1, 50));
                HTP.P(''{"status":"error", "message":"Logout processing failed"}'' );
        END;'
      );

