  ORDS.DEFINE_MODULE(
      p_module_name    => 'user',
      p_base_path      => '/user/',
      p_items_per_page =>  25,
      p_status         => 'PUBLISHED',
      p_comments       => 'User Analytics and Performance APIs');      
  ORDS.DEFINE_TEMPLATE(
      p_module_name    => 'user',
      p_pattern        => 'analytics/:id',
      p_priority       => 0,
      p_etag_type      => 'HASH',
      p_etag_query     => NULL,
      p_comments       => NULL);
  ORDS.DEFINE_HANDLER(
      p_module_name    => 'user',
      p_pattern        => 'analytics/:id',
      p_method         => 'GET',
      p_source_type    => 'json/query',
      p_items_per_page =>  0,
      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'
WITH exercise_types AS (
    SELECT ''MCQ EXERCISES'' AS category_name, 13 AS total, ''MCQ'' AS type FROM dual
    UNION ALL
    SELECT ''MATCH EXERCISES'', 10, ''MATCH'' FROM dual
    UNION ALL
    SELECT ''SEQUENCE EXERCISES'', 3, ''SEQUENCE'' FROM dual
    UNION ALL 
    SELECT ''COMPLETEDWORD EXERCISE'', 3, ''COMPLETEDWORD'' FROM dual
),
raw_attempts AS (
    -- Gather all attempts first, safely converting IDs to numbers
    -- (Requires Oracle 12.2+. If on older version, remove "DEFAULT NULL ON CONVERSION ERROR")
    SELECT TO_NUMBER(user_id DEFAULT NULL ON CONVERSION ERROR) AS user_id, ''MCQ'' AS type, score 
    FROM mcq_attempts WHERE status = ''COMPLETED''
    UNION ALL
    SELECT TO_NUMBER(user_id DEFAULT NULL ON CONVERSION ERROR), ''MATCH'', score 
    FROM matchby_attempts WHERE status = ''COMPLETED''
    UNION ALL
    SELECT TO_NUMBER(user_id DEFAULT NULL ON CONVERSION ERROR), ''SEQUENCE'', score 
    FROM sequence_attempts WHERE status = ''COMPLETED''
    UNION ALL
    SELECT TO_NUMBER(user_id DEFAULT NULL ON CONVERSION ERROR), ''COMPLETEDWORD'', score 
    FROM COMPLETEDWORD_ATTEMPTS WHERE status = ''COMPLETED''
),
user_stats AS (
    SELECT user_id, type, COUNT(*) AS cnt, SUM(score) AS sum_score
    FROM raw_attempts
    WHERE user_id IS NOT NULL
    GROUP BY user_id, type
),
users_with_seq AS (
    SELECT u.*,
           ROW_NUMBER() OVER (ORDER BY TO_NUMBER(u.user_id DEFAULT NULL ON CONVERSION ERROR)) AS user_seq_id
    FROM lms_users u
    WHERE TO_NUMBER(u.user_id DEFAULT NULL ON CONVERSION ERROR) IS NOT NULL
)
SELECT
    e.category_name,
    NVL(s.cnt, 0) AS attempted,
    e.total,
    NVL(s.sum_score, 0) AS score,
    ROUND(NVL(s.cnt,0)/NULLIF(e.total,0)*100, 2) AS percentage,
    CASE
        WHEN ROUND(NVL(s.cnt,0)/NULLIF(e.total,0)*100, 2) < 40 THEN ''danger''
        WHEN ROUND(NVL(s.cnt,0)/NULLIF(e.total,0)*100, 2) BETWEEN 40 AND 70 THEN ''warning''
        ELSE ''success''
    END AS theme_color
FROM users_with_seq u
CROSS JOIN exercise_types e
LEFT JOIN user_stats s
    ON s.user_id = TO_NUMBER(u.user_id)
   AND s.type = e.type
WHERE u.user_seq_id = :id
'
      );
  ORDS.DEFINE_TEMPLATE(
      p_module_name    => 'user',
      p_pattern        => 'performance',
      p_priority       => 0,
      p_etag_type      => 'HASH',
      p_etag_query     => NULL,
      p_comments       => NULL);
  ORDS.DEFINE_HANDLER(
