      p_pattern        => 'performance',
      p_method         => 'GET',
      p_source_type    => 'json/query',
      p_items_per_page =>  0,
      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'WITH all_completions AS (
    SELECT TO_NUMBER(user_id DEFAULT NULL ON CONVERSION ERROR) AS user_id FROM mcq_attempts WHERE status = ''COMPLETED''
    UNION ALL
    SELECT TO_NUMBER(user_id DEFAULT NULL ON CONVERSION ERROR) FROM sequence_attempts WHERE status = ''COMPLETED''
    UNION ALL
    SELECT TO_NUMBER(user_id DEFAULT NULL ON CONVERSION ERROR) FROM matchby_attempts WHERE status = ''COMPLETED''
    UNION ALL
    SELECT TO_NUMBER(user_id DEFAULT NULL ON CONVERSION ERROR) FROM completedword_attempts WHERE status = ''COMPLETED''
),
user_totals AS (
    SELECT user_id, COUNT(*) AS completed_count
    FROM all_completions
    WHERE user_id IS NOT NULL
    GROUP BY user_id
)
SELECT
    ROW_NUMBER() OVER (ORDER BY TO_NUMBER(u.user_id DEFAULT NULL ON CONVERSION ERROR)) AS user_seq_id,

    -- 🟢 FIX: Stitching the new first and last name columns together 
    TRIM(u.c_first_name || '' '' || u.c_last_name) AS user_name,

    u.email,
    NVL(ut.completed_count, 0) AS attempted_exercise,
    29 AS total_exercise
FROM lms_users u
LEFT JOIN user_totals ut
    ON ut.user_id = TO_NUMBER(u.user_id DEFAULT NULL ON CONVERSION ERROR)
WHERE TO_NUMBER(u.user_id DEFAULT NULL ON CONVERSION ERROR) IS NOT NULL
ORDER BY TO_NUMBER(u.user_id DEFAULT NULL ON CONVERSION ERROR)'
      );
  ORDS.DEFINE_TEMPLATE(
      p_module_name    => 'user',
      p_pattern        => 'registration-count',
      p_priority       => 0,
      p_etag_type      => 'HASH',
      p_etag_query     => NULL,
      p_comments       => NULL);
  ORDS.DEFINE_HANDLER(
      p_module_name    => 'user',
      p_pattern        => 'registration-count',
      p_method         => 'GET',
      p_source_type    => 'json/query',
      p_items_per_page =>  0,
      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'
      WITH total_user_activity AS (
          SELECT CAST(user_id AS VARCHAR2(50)) AS user_id, activity_id
          FROM api_dev_user.mcq_attempts
          UNION ALL
          SELECT CAST(user_id AS VARCHAR2(50)), activity_id
          FROM api_dev_user.sequence_attempts
          UNION ALL
          SELECT CAST(user_id AS VARCHAR2(50)), activity_id
          FROM api_dev_user.matchby_attempts
      ),
      user_counts AS (
          SELECT user_id, COUNT(DISTINCT activity_id) AS exercise_count
          FROM total_user_activity
          GROUP BY user_id
      )
      SELECT
          COUNT(l.user_id) AS registrationcount,
          COUNT(CASE WHEN NVL(u.exercise_count, 0) BETWEEN 0 AND 30 THEN 1 END) AS easycount,
          COUNT(CASE WHEN u.exercise_count BETWEEN 31 AND 60 THEN 1 END) AS intermediatecount,
          COUNT(CASE WHEN u.exercise_count BETWEEN 61 AND 90 THEN 1 END) AS hardcount
      FROM api_dev_user.lms_users l
      LEFT JOIN user_counts u
             ON CAST(l.user_id AS VARCHAR2(50)) = u.user_id'
      );

