  ORDS.DEFINE_TEMPLATE(
      p_module_name    => 'v1.konzeptes',
      p_pattern        => 'manage-card',
      p_priority       => 0,
      p_etag_type      => 'HASH',
      p_etag_query     => NULL,
      p_comments       => NULL);
  ORDS.DEFINE_HANDLER(
      p_module_name    => 'v1.konzeptes',
      p_pattern        => 'manage-card',
      p_method         => 'POST',
      p_source_type    => 'plsql/block',
      p_items_per_page =>  0,
      p_mimes_allowed  => '',
      p_comments       => NULL,
      p_source         => 
'
    DECLARE
        v_id_raw   VARCHAR2(50)   := :id;
        v_label    NVARCHAR2(500) := :label;
        v_sm       VARCHAR2(255)  := :smLabel;
        v_id_num   NUMBER;
        v_out_id   NUMBER;
        l_response CLOB;
    BEGIN
        -- Safe Number Conversion
        IF v_id_raw IS NOT NULL AND REGEXP_LIKE(v_id_raw, ''^[0-9]+$'') THEN
            v_id_num := TO_NUMBER(v_id_raw);
        ELSE
            v_id_num := NULL;
        END IF;

        -- UPDATE or INSERT
        IF v_id_num IS NOT NULL AND v_id_num > 0 THEN
            UPDATE CURRICULUM_CARDS
            SET LABEL = v_label, SM_LABEL = v_sm
            WHERE ID = v_id_num
            RETURNING ID INTO v_out_id;
        ELSE
            INSERT INTO CURRICULUM_CARDS (LABEL, SM_LABEL, MIME_TYPE, IMAGE_BLOB, BG_IMAGE_BLOB)
            VALUES (v_label, v_sm, ''image/png'', EMPTY_BLOB(), EMPTY_BLOB())
            RETURNING ID INTO v_out_id;
        END IF;

        -- FORCE JSON RESPONSE
        l_response := ''{"id": '' || v_out_id || '', "status": "success"}'';

        OWA_UTIL.MIME_HEADER(''application/json'', FALSE);
        HTP.P(''Content-Length: '' || DBMS_LOB.GETLENGTH(l_response));
        OWA_UTIL.HTTP_HEADER_CLOSE;
        HTP.P(l_response);

        :status := 200;
    EXCEPTION WHEN OTHERS THEN
        :status := 400; 
    END;'
      );
  ORDS.DEFINE_HANDLER(
      p_module_name    => 'v1.konzeptes',
